text:
{
  "formal_minutes": {
    "project_code": "PUBLIC_MEETING_SMOKE",
    "meeting_title": "UI 테마 패키지 출시 준비 상태 점검",
    "confirmed_decisions": [
      {
        "decision": "공개 출시 목표는 스모크 테스트가 통과하면 금요일 15:00 KST로 한다."
      },
      {
        "decision": "packageName 불일치가 발생하면 먼저 패키지 설정을 확인하고, 계약 자체가 잘못된 경우에만 스크립트를 검토한다."
      }
    ],
    "rejected_proposals": [
      {
        "proposal": "Hara의 smoke-theme-pack.mjs 수정안, 즉 packageName 불일치를 무시하도록 바꾸는 방안은 채택하지 않았다."
      }
    ],
    "internal_stretch_goals": [
      {
        "goal": "수요일 공개를 내부 스트레치 목표로 검토했으나, 최종 확정 일정은 아니며 내부 목표로만 남았다."
      }
    ],
    "non_decisions": [
      {
        "item": "README 설치 단계는 가능하면 목요일까지 검토하자는 의견이 있었지만 담당자가 배정되지 않았다."
      }
    ],
    "risks": [
      {
        "risk": "tarball 경로가 잘못되면 출시가 지연될 수 있다."
      },
      {
        "risk": "README 설치 단계가 오래되면 릴리스 노트가 사용자에게 잘못된 안내를 줄 수 있다."
      }
    ],
    "open_questions": [
      {
        "question": "최종 릴리스 승인 권한자는 누구인가?"
      },
      {
        "question": "릴리스 노트에 내부 수요일 스트레치 목표를 언급할지 여부는 어떻게 할 것인가?"
      }
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "금요일 10:00 KST까지 스모크 테스트를 다시 실행하고 결과를 공유한다.",
      "due": "금요일 10:00 KST",
      "status": "확정",
      "source_certainty": "직접 명시"
    },
    {
      "owner": "Doyun",
      "task": "실패 triage 노트를 `action_items.md`에 작성한다.",
      "due": "금요일 12:00 KST",
      "status": "확정",
      "source_certainty": "직접 명시"
    },
    {
      "owner": "Hara",
      "task": "Minjun이 스모크 결과를 게시한 뒤 생성된 tarball 경로를 확인한다.",
      "due": "Minjun의 스모크 결과 게시 후",
      "status": "대기 중",
      "source_certainty": "직접 명시"
    },
    {
      "owner": "미지정",
      "task": "README 설치 단계를 검토한다.",
      "due": "목요일까지 가능하면",
      "status": "미배정",
      "source_certainty": "직접 명시"
    }
  ],
  "followup_note": "다음 확인 사항은 스모크 테스트 결과, tarball 경로, README 설치 단계, 최종 릴리스 승인 권한자, 그리고 내부 수요일 스트레치 목표의 릴리스 노트 포함 여부다. customer, budget, security incident, production outage, legal approval requirement는 절대 추측하거나 추가하지 말아야 한다.",
  "non_invention_rules": [
    "고객명은 만들지 않는다.",
    "예산 정보는 만들지 않는다.",
    "보안 사고 여부는 만들지 않는다.",
    "프로덕션 장애 여부는 만들지 않는다.",
    "법무 승인 요구 사항은 만들지 않는다.",
    "미지정 담당자를 임의로 지정하지 않는다.",
    "명시되지 않은 정확한 마감 시각을 새로 만들지 않는다.",
    "결정되지 않은 사항을 확정된 사실처럼 쓰지 않는다."
  ]
}
